function solve(nums) {
    const absArr = nums.map(x => Math.abs(x));
    absArr.sort((a, b) => a - b);
    let total = 0;
    const n = absArr.length;
    for (let i = 0; i < n; i++) {
        const target = 2 * absArr[i];
        let left = i + 1;
        let right = n;
        while (left < right) {
            const mid = Math.floor((left + right) / 2);
            if (absArr[mid] > target) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        total += left - (i + 1);
    }
    return total;
}
